VALUES
  ('real-estate-moex-02672', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地所有權移轉，其申報移轉現值之審核標準，以下所述何者正確？', '["申報人於訂定契約之日起三十日內申報者，以受理申報機關收件日當期之公告土地現值為準", "依法院判決移轉登記者，以法院判決宣判日當期之公告土地現值為準", "經法院拍賣之土地，無論拍定價額是否低於公告土地現值，以拍定價額為準", "遺贈之土地，以遺贈人死亡日當期之公告土地現值為準"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 20, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02673', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '依非都市土地使用管制規則，原住民保留地地區住宅興建計畫，由鄉（鎮、市、區）公所整體規劃，經 直轄市或縣（市）政府核准者，於森林區、山坡地保育區、風景區及山坡地範圍內之農業區者，得變更 編定為何種建築用地？', '["甲種建築用地", "乙種建築用地", "丙種建築用地", "丁種建築用地"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02674', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '農業用地閒置不用，經加徵荒地稅滿三年，仍不使用者，得照價收買。照價收買土地之地價，應如何計 算？', '["公告地價", "申報地價", "申報土地移轉現值", "收買當期之公告土地現值"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 22, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02675', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '區域計畫公告實施後，擬定計畫之機關應視實際發展情況，每幾年通盤檢討一次，並作必要之變更？', '["每一年", "每二年", "每五年", "每十年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 23, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02676', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地法規定，政府為開闢交通路線，得為保留徵收，其期間不得超過三年，逾期不徵收，視為廢止。但 得申請核定延長保留徵收期間；其延長期間，以幾年為限？', '["五年", "十年", "十五年", "二十年"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 24, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02677', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '區段徵收之土地以現金補償地價者，每一土地所有權人扣除應納土地增值稅後，總額在多少元以下者，全部 發給現金？', '["五十萬元", "一百萬元", "一百五十萬元", "二百萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 25, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02678', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地徵收條例規定，徵收土地或土地改良物應發給之補償費，應於公告期滿後幾日內發給之？', '["十日", "十五日", "三十日", "六十日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 26, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02679', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '現行土地增值稅之稅率為何？', '["百分之十、百分之二十、百分之三十", "百分之二十、百分之三十、百分之四十", "百分之三十、百分之四十、百分之五十", "百分之四十、百分之五十、百分之六十"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02680', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '平均地權條例規定，為促進土地利用，擴大辦理市地重劃，得獎勵土地所有權人自行組織重劃會辦理之。其 獎勵事項不包括：', '["給予低利之重劃貸款", "免收或減收地籍整理規費及換發權利書狀費用", "優先興建重劃區及其相關地區之公共設施", "免徵或減徵土地增值稅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02681', 'real-estate', 'real-estate-moex-097-629c9966', 'sub-real-estate-03', NULL, 'single_choice', '土地法規定，土地依其使用，得分為各類。下列何者錯誤？', '["建築用地", "直接生產用地", "交通水利用地", "要塞軍備用地"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:13+00:00", "source_pdf_sha1": "76368bb033d1", "answer_pdf_sha1": "4a2f0a558d69", "source_family": "moex-gov-tw", "moex": {"exam_code": "097090", "c": "401", "s": "4001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "土地法與土地相關稅法概要", "year": "097", "exam_name": "097年第一次專技消防設備人員、不動產經紀人、專責報關人員、保險從業人員、中醫師、驗船師考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
